$artjson["ART_faq_fs_q2"] = "What is the rule for tied positions?";  
$artjson["ART_faq_fs_a2_1"] = "If there are two or more winners for a specific event, the payout will be reduced. The calculation is done by dividing the stake by the number of winners and then multiplying it by the original odds. The stake and partial payout will be returned to the member, while the remaining stake will be lost.";  
$artjson["ART_faq_fs_a2_2"] = "For example:";  
$artjson["ART_faq_fs_a2_3"] = "Stage 1 - You bet \u00245.00 at odds of 16.0 (possible payout of \u002475.00)";  
$artjson["ART_faq_fs_a2_4"] = "Stage 2 - Your selected team or individual ties with another winner";  
$artjson["ART_faq_fs_a2_5"] = "Stage 3 - The 'win or lose' calculation for the bet is (stake x odds) / number of winners - stake. Therefore, the 'win or lose' is (\u00245.00 x 16) / 2 – \u00245.00 = \u002435.00.";  
$artjson["ART_faq_fs_a2_6"] = "If there are more than two winners, the stake will be divided accordingly.";  
